    for topic, st, sh, q, opts, ans, exp in gen_more:
        qid += 1
        questions.append({"id": qid, "paper": 1, "year": y, "shift": sh, "topic": topic, "subtopic": st, "question": q, "options": opts, "answer": ans, "explanation": exp})
    
    return questions

